1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	type Item = { type: string; cursed?: boolean };
17	
18	function itemBasePremium(item: Item): number {
19	  const base = BASE_PREMIUMS[item.type];
20	  return item.cursed ? base * (1 + CURSE_SURCHARGE_RATE) : base;
21	}
22	
23	function sumIndividualBasePremiums(items: Item[]): number {
24	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
25	}
26	
27	function groupByType(items: Item[]): Record<string, Item[]> {
28	  const groups: Record<string, Item[]> = {};
29	  for (const item of items) {
30	    if (!groups[item.type]) groups[item.type] = [];
31	    groups[item.type].push(item);
32	  }
33	  return groups;
34	}
35	
36	function premiumForGroup(groupItems: Item[]): number {
37	  return groupItems.length === BLOCK_SIZE
38	    ? BLOCK_OF_THREE_PREMIUM
39	    : sumIndividualBasePremiums(groupItems);
40	}
41	
42	function calculateBasePremium(items: Item[]): number {
43	  const groups = groupByType(items);
44	  return Object.values(groups).reduce((total, group) => total + premiumForGroup(group), 0);
45	}
46	
47	export function quote({ items }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
48	  const basePremium = calculateBasePremium(items);
49	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
50	  return { premium: basePremium + firstInsuranceSurcharges + PROCESSING_FEE };
51	}
52	
53	export function claim(_input: unknown): unknown {
54	  return undefined;
55	}
